  ('social-worker-moex-02811', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關過動兒的敘述中，下列何者最為恰當？', '["過動兒對他人漠不關心，往往視若無睹", "過動兒的成因基本上都是先天的", "過動兒需要環境的一致性和穩定性", "過動兒產生的主因是缺乏注意力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02812', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '當青少年開始探索自我認同課題時，往往也會啟動個體化（individuation）的過程。下列有關個體化的敘 述中，何者不恰當？', '["青少年期的個體化，係指青少年發展出獨特的自我或認同的過程", "青少年期的個體化，就是在生活功能、態度、情緒等等面向朝向自立而不再依附父母安排的過程", "青少年期個體化的過程中，與父母分離的元素，不包括衝突獨立（conflictual independence）", "青少年期的個體化，不僅存在著世代差異，也存在同世代青少年彼此間的個別差異"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02813', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關自閉症者行為表現的特徵，下列敘述何者正確？', '["社會性障礙、溝通障礙、行為興趣的固執性和有限性", "社會性障礙、溝通障礙、情緒障礙", "溝通障礙、情緒障礙、行為興趣的固執性和有限性", "社會性障礙、溝通障礙、心智性障礙"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02814', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何種理論認為：兒童期是道德發展關鍵期，若能在其生活環境中有適當長輩可供模仿和予以適當指 導，則上行下效，有助提升兒童的道德認知水準？', '["近側最佳化發展區理論", "皮亞傑（Piaget）的道德認知發展理論", "柯柏格（Kohlberg）的道德認知發展理論", "近朱者赤之品格教育理論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02815', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '探討性別議題的學者認為，中年危機主要是女性的常態過程，對於男性而言則較少發生，其主要理由乃：', '["女性會有更年期，男性則無", "中年期親職負擔減輕後，因為婦女的角色比男人多樣和複雜，其角色重整的難度相對較高", "一般而言，中年期男人比婦女擁有較多權力和資源，較不易感受變遷壓力和危機", "兩性的生理和心理結構存在本質的差異，中年期的婦女調適相對不易"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02816', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關中年期特徵之描述中，下列何者錯誤？', '["相對於其他階段而言，中年期的人們較少受到生理變化的影響", "由於可塑性小，相對於其他階段而言，中年期是人們在個別經驗上彼此差異最小的時期", "由於個別差異趨大，按特定的年齡來界定中年期，已經越來越不恰當", "不同世代的中年人，會受其所處環境和歷史事件的影響，而呈現明顯差異"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02817', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依佛洛伊德（Sigmund Freud）的理論，年滿50歲以上的人，其人格特質會呈現下列何種特性？', '["會隨年紀增長而持續變遷調適", "女性的改變比男性改變的可能性大", "不同文化族群者會有不同差異，不能一概而論", "已經定型，不易改變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02818', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依柯柏格（Kohlberg）的道德發展理論，下列敘述何者最能描述5歲兒童的行為特性？', '["能按簡單的社會規範表現行為", "還停留在無律階段，行為沒有一定的規律性", "會基於避免被懲罰來表現行為", "主要依賞罰的條件來調整行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02819', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依皮亞傑（Piaget）認知發展理論，下列何者最能適切描述10歲左右兒童的認知發展情形？', '["已經有抽象邏輯分析推理的能力", "已經能使用語言及符號等來體驗世界", "已經能夠從事物的分類、比較以了解其間的關係", "已經發展出物體恆存的概念"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02820', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '許多兒童在歷經多次失敗後，認為再多的努力也無濟於事，就不再繼續嘗試。兒童的此種行為現象，被 稱為：', '["他發型無力感", "內化的挫折感", "習得的無助感", "自我剝奪感"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
